WITH pattern_union_r AS (
SELECT 'User' AS start_type, toString(test_integration.users_test.user_id) as start_id, toString(test_integration.posts_test.post_id) as end_id, 'Post' AS end_type, ['AUTHORED'] as path_relationships, ['{}'] as rel_properties, formatRowNoNewline('JSONEachRow', test_integration.users_test.age, test_integration.users_test.city, test_integration.users_test.country, test_integration.users_test.email_address, test_integration.users_test.is_active, test_integration.users_test.full_name, test_integration.users_test.registration_date, test_integration.users_test.user_id) as start_properties, formatRowNoNewline('JSONEachRow', test_integration.posts_test.author_id, test_integration.posts_test.post_content, test_integration.posts_test.post_date, test_integration.posts_test.post_id, test_integration.posts_test.post_title) as end_properties, NULL AS follow_date, NULL AS like_date FROM test_integration.posts_test INNER JOIN test_integration.users_test ON test_integration.users_test.user_id = test_integration.posts_test.author_id
UNION ALL
SELECT 'User' AS start_type, toString(from_node.user_id) as start_id, toString(to_node.user_id) as end_id, 'User' AS end_type, ['FOLLOWS'] as path_relationships, [formatRowNoNewline('JSONEachRow', test_integration.user_follows_test.follow_date AS follow_date)] as rel_properties, formatRowNoNewline('JSONEachRow', from_node.age, from_node.city, from_node.country, from_node.email_address, from_node.is_active, from_node.full_name, from_node.registration_date, from_node.user_id) as start_properties, formatRowNoNewline('JSONEachRow', to_node.age, to_node.city, to_node.country, to_node.email_address, to_node.is_active, to_node.full_name, to_node.registration_date, to_node.user_id) as end_properties, test_integration.user_follows_test.follow_date AS follow_date, NULL AS like_date FROM test_integration.user_follows_test INNER JOIN test_integration.users_test AS from_node ON from_node.user_id = test_integration.user_follows_test.follower_id INNER JOIN test_integration.users_test AS to_node ON to_node.user_id = test_integration.user_follows_test.followed_id
UNION ALL
SELECT 'User' AS start_type, toString(test_integration.users_test.user_id) as start_id, toString(test_integration.posts_test.post_id) as end_id, 'Post' AS end_type, ['LIKED'] as path_relationships, [formatRowNoNewline('JSONEachRow', test_integration.post_likes_test.like_date AS like_date)] as rel_properties, formatRowNoNewline('JSONEachRow', test_integration.users_test.age, test_integration.users_test.city, test_integration.users_test.country, test_integration.users_test.email_address, test_integration.users_test.is_active, test_integration.users_test.full_name, test_integration.users_test.registration_date, test_integration.users_test.user_id) as start_properties, formatRowNoNewline('JSONEachRow', test_integration.posts_test.author_id, test_integration.posts_test.post_content, test_integration.posts_test.post_date, test_integration.posts_test.post_id, test_integration.posts_test.post_title) as end_properties, NULL AS follow_date, test_integration.post_likes_test.like_date AS like_date FROM test_integration.post_likes_test INNER JOIN test_integration.users_test ON test_integration.users_test.user_id = test_integration.post_likes_test.user_id INNER JOIN test_integration.posts_test ON test_integration.posts_test.post_id = test_integration.post_likes_test.post_id
)
SELECT 
      count(*) AS "total"
FROM pattern_union_r AS r
